		long estimatedBytes = estimateBytes((long) predCard);
		if (estimatedBytes > maxEntryBytes()) {
			recordRefusal();
			return;
		}
		if (!admitBuild(slot, predCard, estimatedBytes)) {
			return;
		}
		if (!slot.building.compareAndSet(false, true)) {
			return;
		}
